    /**
     * Get just the country names for the countries dropdown
     * Returns: [country_id => 'Country Name']
     */
    public static function getCountries()
    {
        return array_map(function($item) {
            return $item['name'];
        }, self::getCountriesWithCodes());
    }

    /**
     * Get phone codes with country names
     * Returns: [phone_code => 'Country Name (+code)']
     */
    public static function getPhoneCodes()
    {
        $phone_codes = [];
        foreach (self::getCountriesWithCodes() as $id => $country_data) {
            $code = $country_data['code'];
            if (!isset($phone_codes[$code])) {
                $phone_codes[$code] = $country_data['name'] . ' (+' . $code . ')';
            }
        }
        return $phone_codes;
    }

    public static function getCountryPhoneMap()
    {
        $country_phone_map = [];
        foreach (self::getCountriesWithCodes() as $id => $country_data) {
            $country_phone_map[$id] = $country_data['code'];
        }
        return $country_phone_map;
    }
